#include <stdio.h>
#include <stdlib.h>
#define MAX 100001
int visited[MAX];
int recStack[MAX];
int adj[MAX][MAX];
int n;

void dfs(int node) {
    visited[node] = 1;
    recStack[node] = 1;
    for (int i = 0; i < n; i++) {
        if (adj[node][i] && !visited[i]) {
            dfs(i);
        } else if (adj[node][i] && recStack[i]) {
            // cycle detected
        }
    }
    recStack[node] = 0;
}

int main() {
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        int node, neighbor;
        scanf("%d", &node);
        while (scanf("%d", &neighbor) == 1) {
            adj[node - 1][neighbor - 1] = 1;
        }
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            dfs(i);
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

